# Generated by Claude on 2026-05-13 for task 08. Prompt: thesis_prompts/08_limo_ros2_topics_roundtrip.md
#
# Background: the original prompt asked the agent to "connect through ROS MCP",
# but no ROS-specific MCP tool surface was available on this server. The agent
# fell back to using rclpy directly inside Isaac Sim's Python environment via
# isaac-sim:execute_script. This file is a reconstruction of that inline
# session as a saveable script, so the evidence bundle has a concrete artifact.
#
# The session was split across multiple execute_script calls in practice
# (list topics -> subscribe and classify -> publish cmd_vel -> read odom);
# the helper functions below reflect that decomposition.
"""
LIMO ROS 2 round-trip:
  1. List all live topics.
  2. Classify camera / LiDAR / cmd_vel / odom topics by message type.
  3. Subscribe to LiDAR and decide whether the front sector is clear.
  4. If clear, publish forward Twist for 2 s, then a zero Twist.
  5. Compare odometry before/after to confirm motion.

Everything runs inside Isaac Sim's already-initialised rclpy node context;
we do not call rclpy.init()/shutdown() because the ROS 2 bridge owns the
context for the duration of the scene.
"""

from __future__ import annotations

import math
import time

import rclpy
from rclpy.node import Node
from rclpy.qos import QoSProfile, QoSReliabilityPolicy, QoSHistoryPolicy

from geometry_msgs.msg import Twist
from sensor_msgs.msg import LaserScan, Image
from nav_msgs.msg import Odometry


# Topic-classification heuristic: match by message type, not by name string.
# This keeps the code working even if the user has renamed topics (e.g.
# /limo/cmd_vel vs /cmd_vel).
TYPE_MAP = {
    "camera": "sensor_msgs/msg/Image",
    "lidar":  "sensor_msgs/msg/LaserScan",
    "cmd_vel": "geometry_msgs/msg/Twist",
    "odom":   "nav_msgs/msg/Odometry",
}


# --------------------------------------------------------------------------
# Topic discovery
# --------------------------------------------------------------------------
def classify_topics(node: Node) -> dict[str, str | None]:
    """Return {role: topic_name} for the four target roles, or None if missing."""
    # get_topic_names_and_types() returns [(name, [type, ...]), ...]
    raw = node.get_topic_names_and_types()
    out = {role: None for role in TYPE_MAP}
    for name, types in raw:
        for role, want in TYPE_MAP.items():
            if want in types and out[role] is None:
                out[role] = name
    return out


# --------------------------------------------------------------------------
# LiDAR clearance check
# --------------------------------------------------------------------------
def lidar_front_is_clear(node: Node, topic: str,
                         half_fov_deg: float = 15.0,
                         min_clearance: float = 0.5,
                         timeout: float = 2.0) -> tuple[bool, float] | None:
    """
    Subscribe briefly to LaserScan, take one message, and decide whether the
    front sector (±half_fov_deg around angle 0) contains any return closer
    than min_clearance metres.

    Returns (is_clear, min_range_in_front) or None if no message arrives.
    Different LaserScan publishers use different angle conventions, so we
    compute the front window from the message's own angle_min/angle_increment
    rather than assuming a fixed index range.
    """
    received: dict[str, LaserScan] = {}

    def cb(msg: LaserScan):
        received["msg"] = msg

    sub = node.create_subscription(LaserScan, topic, cb, qos_profile_sensor_data_qos())
    deadline = time.time() + timeout
    while time.time() < deadline and "msg" not in received:
        rclpy.spin_once(node, timeout_sec=0.05)
    node.destroy_subscription(sub)

    if "msg" not in received:
        return None

    msg = received["msg"]
    half_fov = math.radians(half_fov_deg)
    front_ranges = []
    for i, r in enumerate(msg.ranges):
        angle = msg.angle_min + i * msg.angle_increment
        # normalise to [-pi, pi]
        while angle > math.pi:
            angle -= 2 * math.pi
        while angle < -math.pi:
            angle += 2 * math.pi
        if -half_fov <= angle <= half_fov:
            if math.isfinite(r) and msg.range_min <= r <= msg.range_max:
                front_ranges.append(r)
    if not front_ranges:
        return (True, float("inf"))   # no returns in the front window -> clear
    min_r = min(front_ranges)
    return (min_r > min_clearance, min_r)


def qos_profile_sensor_data_qos() -> QoSProfile:
    """Sensor-data QoS (best-effort, keep-last-10) — what Isaac's ROS 2 bridge
    publishes scans/images with."""
    return QoSProfile(
        reliability=QoSReliabilityPolicy.BEST_EFFORT,
        history=QoSHistoryPolicy.KEEP_LAST,
        depth=10,
    )


# --------------------------------------------------------------------------
# cmd_vel publish + odom sample
# --------------------------------------------------------------------------
def latest_odom(node: Node, topic: str, timeout: float = 2.0) -> Odometry | None:
    received: dict[str, Odometry] = {}

    def cb(msg: Odometry):
        received["msg"] = msg

    sub = node.create_subscription(Odometry, topic, cb, 10)
    deadline = time.time() + timeout
    while time.time() < deadline and "msg" not in received:
        rclpy.spin_once(node, timeout_sec=0.05)
    node.destroy_subscription(sub)
    return received.get("msg")


def drive_forward_then_stop(node: Node, cmd_topic: str,
                            seconds: float = 2.0,
                            linear_x: float = 0.15) -> None:
    pub = node.create_publisher(Twist, cmd_topic, 10)
    twist = Twist()
    twist.linear.x = linear_x

    # Publish at 20 Hz for the requested duration
    end = time.time() + seconds
    while time.time() < end:
        pub.publish(twist)
        rclpy.spin_once(node, timeout_sec=0.05)

    # Brake: publish a few zero Twists to be sure the controller saw it
    twist = Twist()  # all zeros
    for _ in range(10):
        pub.publish(twist)
        rclpy.spin_once(node, timeout_sec=0.05)

    node.destroy_publisher(pub)


# --------------------------------------------------------------------------
# Orchestration (this is what execute_script ran end-to-end)
# --------------------------------------------------------------------------
def run() -> dict:
    """Driver. Returns a result dict the agent can summarise from."""
    node = rclpy.create_node("limo_round_trip_helper")
    try:
        topics = classify_topics(node)
        print(f"[ros2_rt] classified topics: {topics}")
        if not topics["lidar"] or not topics["cmd_vel"] or not topics["odom"]:
            return {"status": "missing_topic", "topics": topics}

        clearance = lidar_front_is_clear(node, topics["lidar"])
        if clearance is None:
            return {"status": "no_lidar_msg", "topics": topics}
        is_clear, min_r = clearance
        print(f"[ros2_rt] front min_range={min_r:.2f} m, clear={is_clear}")

        if not is_clear:
            return {"status": "blocked", "front_min_range_m": min_r}

        before = latest_odom(node, topics["odom"])
        drive_forward_then_stop(node, topics["cmd_vel"], seconds=2.0, linear_x=0.15)
        after = latest_odom(node, topics["odom"])

        if before is None or after is None:
            return {"status": "no_odom_msg"}

        dx = after.pose.pose.position.x - before.pose.pose.position.x
        dy = after.pose.pose.position.y - before.pose.pose.position.y
        dist = math.hypot(dx, dy)
        print(f"[ros2_rt] odom delta: dx={dx:+.3f} dy={dy:+.3f} dist={dist:.3f} m")

        return {
            "status": "ok",
            "topics": topics,
            "front_min_range_m": min_r,
            "odom_delta_m": {"dx": dx, "dy": dy, "dist": dist},
        }
    finally:
        node.destroy_node()


if __name__ == "__main__":
    print(run())
